import type { FetchHubSpotApiRequest, FetchHubSpotApiResponse } from './api-client.ts';
import type { FormatCrmPropertiesRequest } from './crm.ts';
import type { HubspotExtendFunction } from './extend.ts';
import type { ExtensionPointApiActions, ExtensionPointApiContext, ExtensionPointFullApi, ExtensionPoints } from './extension-points.ts';
import type { CrmPropertiesResponse, FetchAssociationsRequest, FetchCrmSearchRequest, FetchHookOptions } from './hooks.ts';
import type { Logger } from './logger.ts';
import type { AppPageLocation } from './shared.ts';
export interface WorkersApi {
    /**
     * Hook added to worker globals so customer code can access extension context at runtime.
     */
    useExtensionContext: <ExtensionPoint extends keyof ExtensionPoints>() => ExtensionPointApiContext<ExtensionPoint>;
    /**
     * Hook added to worker globals so customer code can access extension actions at runtime.
     */
    useExtensionActions: <ExtensionPoint extends keyof ExtensionPoints>() => ExtensionPointApiActions<ExtensionPoint>;
    /**
     * Hook added to worker globals so customer code can access extension API at runtime.
     */
    useExtensionApi: <ExtensionPoint extends keyof ExtensionPoints>() => ExtensionPointFullApi<ExtensionPoint>;
    /**
     * Hook added to worker globals so page router can access the current app page location at runtime.
     */
    useAppPageLocation: () => AppPageLocation;
    /**
     * Runner for the CRM search hook, proxies search requests to the host.
     */
    fetchCrmSearch: (request: FetchCrmSearchRequest, options?: FetchHookOptions) => Promise<Response>;
    /**
     * Runner for the CRM properties hook, proxies property requests to the host.
     */
    fetchCrmProperties: (properties: string[], propertiesUpdatedCallback: (properties: CrmPropertiesResponse) => void, options?: FetchHookOptions) => Promise<Response>;
    /**
     * Runner for the associations hook, proxies association requests to the host.
     */
    fetchAssociations: (request: FetchAssociationsRequest, options?: FetchHookOptions) => Promise<Response>;
    /**
     * Runner for the experimental HubSpot API client, proxies arbitrary
     * HubSpot public API requests to the host.
     */
    fetchHubSpotApi: (request: FetchHubSpotApiRequest) => Promise<FetchHubSpotApiResponse>;
    /**
     * Formats CRM property values using HubSpot's display formatting rules.
     * Proxies the formatting request to the host where I18n and property metadata are available.
     */
    formatCrmProperties: (request: FormatCrmPropertiesRequest) => Promise<Response>;
}
export interface WorkerGlobalsInternal {
    /**
     * A marker that the current global is a HubSpot extension worker.
     */
    __HUBSPOT_EXTENSION_WORKER__?: boolean;
    /**
     * A logger for the current worker.
     */
    logger: Logger;
    /**
     * A global function in worker globals that is used to extend the current worker with a new extension point.
     * NOTE: `extend_V2` is used internally by `hubspot.extend` (where `hubspot` is imported from `@hubspot/ui-extensions`).
     */
    extend_V2: HubspotExtendFunction;
    /**
     * Namespace where all HubSpot APIs that go on the worker should live.
     * This avoids polluting the global and reduces the possibility of customer code having collisions with our code.
     */
    hsWorkerAPI: WorkersApi;
}
